member.example:
Bind the slider's full range to a Vector2 ViewModel property using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SliderMinMaxBinder _range;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bindable]
        private Vector2 _range;
    }


Bind only the minimum endpoint of the slider range in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Slider _slider;
        
        private SliderMinMaxBinder MinRange => new(_slider, SliderValueMode.Min);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bindable]
        private Vector2 _range;
    }

Bind the slider's range to a Vector2 ViewModel property using a MonoBinder component assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SliderMinMaxMonoBinder _range;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bindable]
        private Vector2 _range;
    }

Switch the slider's min/max range between two values using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private SliderMinMaxSwitcherBinder _isDifficult;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bindable]
        private bool _isDifficult;
    }


Switch the slider's min/max range between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private Slider _slider;
        
        [SerializeField]    
        private Vector2 _hardRange;
        
        [SerializeField] 
        private Vector2 _easyRange;
        
        private SliderMinMaxSwitcherBinder IsDifficult => new(
            _slider, _hardRange, _easyRange);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bindable]
        private bool _isDifficult;
    }
